// Extract the most relevant year from a timeline string ("June 2024 - Present", "2025", "Jan 2025 - Present")
const extractYear = (timeline) => {
  if (!timeline) return null;
  if (/present/i.test(timeline)) {
    const matches = timeline.match(/(20\d{2})/g);
    if (matches && matches.length) return matches[matches.length - 1];
    return "Present";
  }
  const matches = timeline.match(/(20\d{2})/g);
  if (!matches) return null;
  return matches[matches.length - 1];
};

// Build a haystack string for searching/filtering a single project
const buildHaystack = (project) => {
  const techNames = (project.languages || [])
    .map((l) => (l.name || "").toLowerCase())
    .join(" ");
  return `${(project.name || "").toLowerCase()} ${(project.description || "")
    .toLowerCase()} ${techNames}`;
};

const matchesCategory = (project, categoryId) => {
  if (categoryId === "ALL") return true;
  const cat = FILTER_CATEGORIES.find((c) => c.id === categoryId);
  if (!cat || !cat.keywords) return true;
  const hay = buildHaystack(project);
  return cat.keywords.some((kw) => hay.includes(kw.toLowerCase()));
};

const matchesSearch = (project, query) => {
  const q = query.trim().toLowerCase();
  if (!q) return true;
  return buildHaystack(project).includes(q);
};

function Projects(props) {
  const theme = props.theme;
  const [selectedProject, setSelectedProject] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState("ALL");
  const [searchQuery, setSearchQuery] = useState("");
  const [stickerIndex, setStickerIndex] = useState(0);

  // Cycle through the 3 sticker GIFs every 8s
  useEffect(() => {
    const id = setInterval(() => {
      setStickerIndex((i) => (i + 1) % stickers.length);
    }, 8000);
    return () => clearInterval(id);
  }, []);

  // Featured = first 3 projects in data (CAMS Lens, CAMSCode, IDP)
  const featuredProjects = useMemo(
    () => (projects.data || []).slice(0, 3),
    []
  );
  const restProjects = useMemo(() => (projects.data || []).slice(3), []);

  // Aggregate metrics for the stat strip — computed once
  const stats = useMemo(() => {
    const all = projects.data || [];
    const ai = all.filter((p) => matchesCategory(p, "AI")).length;
    const production = all.filter((p) =>
      /present/i.test(p?.details?.timeline || "")
    ).length;
    // Count distinct news-covered projects
    const covered = all.filter(
      (p) => Array.isArray(p?.details?.newsLinks) && p.details.newsLinks.length
    ).length;
    return {
      total: all.length,
      ai,
      production,
      covered: covered || 1, // at minimum CAMS Lens
    };
  }, []);

  // Filter logic — applied to non-featured cards
  const filteredProjects = useMemo(() => {
    return restProjects.filter(
      (p) => matchesCategory(p, activeCategory) && matchesSearch(p, searchQuery)
    );
  }, [restProjects, activeCategory, searchQuery]);

  // Handle "Explore" / Modal
  const handleExplore = useCallback((project) => {
    setSelectedProject(project);
    setIsModalOpen(true);
  }, []);

  const closeModal = useCallback(() => {
    setIsModalOpen(false);
    setTimeout(() => setSelectedProject(null), 300);
  }, []);

  return (
    <div className="projects-main" data-theme={theme?.name}>
      <Header theme={theme} setTheme={props.setTheme} />

      {/* ============= HERO ============= */}
      <div className="basic-projects">
        <Fade bottom duration={2000} distance="40px">
          <div className="projects-heading-div">
            <div className="projects-heading-img-div">
              <ProjectsImg theme={theme} />
            </div>
            <div className="projects-heading-text-div">
              <h1
                className="projects-heading-text"
                style={{ color: theme.text }}
              >
                Projects
                <span className="projects-count-badge">{stats.total}</span>
                <img
                  className="projects-hero-sticker"
                  src={stickers[stickerIndex]}
                  alt=""
                  aria-hidden="true"
                />
              </h1>
              <p
                className="projects-header-detail-text subTitle"
                style={{ color: theme.secondaryText }}
              >
                {projectsHeader["description"]}
              </p>

              {/* === Quantified stat strip === */}
              <div className="projects-stat-strip">
                <div className="proj-stat">
                  <div className="proj-stat-num">{stats.total}+</div>
                  <div className="proj-stat-label">projects shipped</div>
                </div>
                <div className="proj-stat">
                  <div className="proj-stat-num">{stats.ai}+</div>
                  <div className="proj-stat-label">AI / agentic</div>
                </div>
                <div className="proj-stat">
                  <div className="proj-stat-num">4</div>
                  <div className="proj-stat-label">in production</div>
                </div>
                <div className="proj-stat">
                  <div className="proj-stat-num">{stats.covered}</div>
                  <div className="proj-stat-label">publicly covered</div>
                </div>
              </div>
            </div>
          </div>
        </Fade>
      </div>

      {/* ============= FEATURED ============= */}
      {featuredProjects.length > 0 && (
        <section className="featured-projects-section">
          <div className="featured-projects-header">
            <h2 className="featured-projects-title">
              <span className="featured-pulse" aria-hidden="true" /> Featured
            </h2>
            <p className="featured-projects-sub" style={{ color: theme.secondaryText }}>
              Production-grade work I'm most proud of
            </p>
          </div>
          <div className="repo-cards-div-main featured-grid">
            {featuredProjects.map((repo) => (
              <ProjectCard
                key={`featured-${repo.id}`}
                repo={repo}
                theme={theme}
                onExplore={handleExplore}
                featured
              />
            ))}
          </div>
        </section>
      )}

      {/* ============= FILTER + SEARCH BAR ============= */}
      <section className="projects-toolbar">
        <div className="projects-toolbar-inner">
          <div className="projects-filter-pills" role="tablist" aria-label="Filter projects">
            {FILTER_CATEGORIES.map((cat) => {
              const count =
                cat.id === "ALL"
                  ? restProjects.length
                  : restProjects.filter((p) => matchesCategory(p, cat.id))
                      .length;
              const isActive = activeCategory === cat.id;
              return (
                <button
                  key={cat.id}
                  type="button"
                  role="tab"
                  aria-selected={isActive}
                  className={`projects-filter-pill ${isActive ? "active" : ""}`}
                  onClick={() => setActiveCategory(cat.id)}
                >
                  {cat.label}
                  <span className="projects-filter-count">{count}</span>
                </button>
              );
            })}
          </div>

          <div className="projects-search-wrap">
            <FaSearch className="projects-search-icon" aria-hidden="true" />
            <input
              type="search"
              className="projects-search-input"
              placeholder="Search projects, tech, keywords…"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              aria-label="Search projects"
            />
          </div>
        </div>
      </section>

      {/* ============= GRID ============= */}
      <div className="repo-cards-div-main projects-grid">
        {filteredProjects.length === 0 ? (
          <div className="projects-empty-state">
            <p>No projects match this filter.</p>
            <button
              type="button"
              className="projects-empty-reset"
              onClick={() => {
                setActiveCategory("ALL");
                setSearchQuery("");
              }}
            >
              Reset filters
            </button>
          </div>
        ) : (
          filteredProjects.map((repo) => (
            <ProjectCard
              key={repo.id}
              repo={repo}
              theme={theme}
              onExplore={handleExplore}
            />
          ))
        )}
      </div>

      {/* ============= MODAL ============= */}
      <React.Suspense fallback={null}>
        <ProjectModal
          project={selectedProject}
          theme={theme}
          isOpen={isModalOpen}
          onClose={closeModal}
        />
      </React.Suspense>

      {/* ============= MORE ON GITHUB ============= */}
      <div className="projects-more-row">
        <a
          className="general-btn"
          href={socialMediaLinks.github}
          target="_blank"
          rel="noopener noreferrer"
        >
          More projects on GitHub →
        </a>
      </div>

      <Footer theme={props.theme} onToggle={props.onToggle} />
    </div>
  );
}

export { extractYear };
export default Projects;
