import React, { memo, useRef, useCallback } from "react";
import ProjectLanguages from "../projectLanguages/ProjectLanguages";
import "./ProjectCard.css";
import { FaExternalLinkAlt, FaGithub } from "react-icons/fa";
import { VscCode } from "react-icons/vsc";
import { useInView } from "react-intersection-observer";

// Pull the most relevant year out of a timeline string
const yearFromTimeline = (timeline) => {
  if (!timeline) return null;
  if (/present/i.test(timeline)) {
    const m = timeline.match(/(20\d{2})/g);
    return m && m.length ? m[m.length - 1] : "Present";
  }
  const m = timeline.match(/(20\d{2})/g);
  return m && m.length ? m[m.length - 1] : null;
};

const ProjectCard = memo(({ repo, theme, onExplore, featured }) => {
  const [ref, inView] = useInView({
    triggerOnce: true,
    threshold: 0.1,
  });

  const cardRef = useRef(null);
  const rafRef = useRef(null);

  const year = yearFromTimeline(repo?.details?.timeline);
  const topImpact =
    repo?.details?.impact && repo.details.impact.length > 0
      ? repo.details.impact[0]
      : null;
  const isOngoing = /present/i.test(repo?.details?.timeline || "");

  function openInNewTab(url) {
    if (!url) return;
    const win = window.open(url, "_blank", "noopener,noreferrer");
    if (win) win.focus();
  }

  // Parallax 3D Tilt — tracks mouse relative to card center
  const handleMouseMove = useCallback((e) => {
    if (!cardRef.current) return;

    // Cancel any pending frame
    if (rafRef.current) cancelAnimationFrame(rafRef.current);

    rafRef.current = requestAnimationFrame(() => {
      const card = cardRef.current;
      if (!card) return;
      const rect = card.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      const centerX = rect.width / 2;
      const centerY = rect.height / 2;

      // Apply Spotlight Coordinates
      card.style.setProperty("--mouse-x", `${x}px`);
      card.style.setProperty("--mouse-y", `${y}px`);

      // Tilt range: ±6 degrees to keep it subtle
      const rotateY = ((x - centerX) / centerX) * 6;
      const rotateX = ((centerY - y) / centerY) * -6; // Inverted for natural tilt

      card.style.transform = `
        perspective(800px)
        rotateX(${rotateX}deg)
        rotateY(${rotateY}deg)
        translateY(-8px)
        scale(1.02)
      `;
    });
  }, []);

  const handleMouseLeave = useCallback(() => {
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    if (cardRef.current) {
      cardRef.current.style.transform = "";
    }
  }, []);

  const handleLiveClick = (e) => {
    e.stopPropagation();
    openInNewTab(repo.url);
  };

  const handleExploreClick = (e) => {
    e.stopPropagation();
    if (onExplore) onExplore(repo);
  };

  const isGitHub = repo.url?.includes("github.com");

  return (
    <div
      ref={ref}
      className={`project-card-wrapper ${inView ? "visible" : ""} ${
        featured ? "featured" : ""
      }`}
    >
      <div
        ref={cardRef}
        className={`project-card ${featured ? "featured" : ""}`}
        onClick={() => openInNewTab(repo.url)}
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        style={{ backgroundColor: theme.projectCard }}
      >
        {/* Dynamic Spotlight Glow */}
        <div className="card-spotlight" />

        {/* Top accent glow line */}
        <div className="card-accent-line" />

        {/* Year + status badges (top-right) */}
        {(year || featured) && (
          <div className="card-meta-badges">
            {featured && <span className="card-badge featured-badge">Featured</span>}
            {year && (
              <span className={`card-badge year-badge ${isOngoing ? "ongoing" : ""}`}>
                {isOngoing && <span className="ongoing-dot" aria-hidden="true" />}
                {year}
              </span>
            )}
          </div>
        )}

        <div className="repo-name-div">
          <p className="repo-name" style={{ color: theme.text }}>
            {repo.name}
          </p>

          <div className="project-buttons">
            <button
              className="live-button"
              onClick={handleLiveClick}
              title={isGitHub ? "View on GitHub" : "View Live Demo"}
              style={{
                backgroundColor: theme.accentColor,
                color: "#fff",
              }}
            >
              {!isGitHub && <span className="live-dot"></span>}
              {isGitHub ? (
                <>
                  <FaGithub style={{ marginRight: 3 }} />
                  GitHub
                </>
              ) : (
                <>
                  <FaExternalLinkAlt style={{ marginRight: 3 }} />
                  Live
                </>
              )}
            </button>

            <button
              className="live-button secondary-button"
              onClick={handleExploreClick}
              title="Explore project details"
              style={{
                backgroundColor: "transparent",
                color: theme.accentColor,
                border: `1px solid ${theme.accentColor}`,
              }}
            >
              <VscCode style={{ marginRight: 3 }} />
              Source
            </button>
          </div>
        </div>

        <p className="repo-description" style={{ color: theme.text }}>
          {repo.description}
        </p>

        {/* Top impact metric — recruiter-friendly hook */}
        {topImpact && (
          <div className="card-impact" title={topImpact}>
            <span className="card-impact-icon" aria-hidden="true">★</span>
            <span className="card-impact-text">{topImpact}</span>
          </div>
        )}

        <div className="repo-details">
          <ProjectLanguages logos={repo.languages} />
        </div>
      </div>
    </div>
  );
});

export default ProjectCard;
